const iconMap = {
    Star, Music, Users, MapPin, CloudRain, Heart, FileEdit, Layout,
    Utensils, Wine, Zap, Flame, Cloud, PartyPopper, Gift, Gamepad2,
    Gem, Video, Camera, Bus, ShieldCheck, Flower, Martini, Mic, Sparkles,
    Info, ExternalLink, Pencil, Trash2, Plus, X, Eye, Search, CheckCircle2, Circle,
    Novia, Novio, Cortejo, SalidaCeremonia, RamoIcon, Soltero, Zapatilla,
    Crown, Coffee, Cake, Flower2
};

const KeyItemsManager = ({ keyItems = [], onUpdate, onDelete, userRol, eventType, baseItems = {} }) => {
    const [showBank, setShowBank] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');

    // Categorizar items actuales
    const categories = keyItems.reduce((acc, item) => {
        const cat = item.categoria || 'General';
        if (!acc[cat]) acc[cat] = [];
        acc[cat].push(item);
        return acc;
    }, {});

    const renderIcon = (iconName, size = 16) => {
        if (!iconName) return <Star size={size} opacity={0.5} />;

        const search = String(iconName).toLowerCase();

        // Comprehensive map to handle variations and legacy names
        const internalMap = {
            ...iconMap,
            'map-pin': MapPin,
            'mappin': MapPin,
            'mappl_in': MapPin,
            'cloud-rain': CloudRain,
            'cloudrain': CloudRain,
            'layout': Layout,
            'file-edit': FileEdit,
            'fileedit': FileEdit,
            'video': Video,
            'bus': Bus,
            'shield-check': ShieldCheck,
            'shieldcheck': ShieldCheck,
            'flower': Flower,
            'martini': Martini,
            'mic': Mic,
            'sparkles': Sparkles,
            'zap': Zap,
            'flame': Flame,
            'cloud': Cloud,
            'novio': Novio,
            'novia': Novia,
            'cortejo': Cortejo,
            'salidaceremonia': SalidaCeremonia,
            'ramoicon': RamoIcon,
            'ramo': RamoIcon,
            'soltero': Soltero,
            'zapatilla': Zapatilla,
            'zapatillaicon': Zapatilla
        };

        const key = Object.keys(internalMap).find(k => k.toLowerCase() === search);
        const IconComponent = internalMap[key] || Star;
        return <IconComponent size={size} />;
    };

    const handleView = (item) => {
        Swal.fire({
            title: item.titulo.toUpperCase(),
            html: `
                <div class="swal-v4-view">
                    <div class="view-section">
                        <label>Categoría</label>
                        <p>${item.categoria || 'Sin categoría'}</p>
                    </div>
                    <div class="view-section">
                        <label>Descripción / Contenido</label>
                        <p class="view-content-text">${item.valor || 'Sin descripción detallada...'}</p>
                    </div>
                    ${item.enlace ? `
                    <div class="view-section">
                        <label>Enlace / URL</label>
                        <div class="view-link-display">
                            <span class="url-text">${item.enlace}</span>
                        </div>
                    </div>` : ''}
                </div>
            `,
            background: 'var(--color-bg)',
            color: 'var(--color-text)',
            confirmButtonColor: 'var(--color-primary)',
            confirmButtonText: 'CERRAR',
            customClass: {
                popup: 'swal2-v4-popup'
            }
        });
    };

    const handleEdit = async (item) => {
        const { value: formValues } = await Swal.fire({
            title: 'EDITAR PUNTO CLAVE',
            html: `
                <div class="swal-v4-form">
                    <div class="form-field is-floating">
                        <input id="swal-key-titulo" class="dense-input" placeholder=" " value="${item.titulo}">
                        <label>Título del Punto</label>
                    </div>
                    <div class="form-grid-2">
                        <div class="form-field is-floating">
                            <select id="swal-key-tipo" class="dense-input">
                                <option value="Link" ${item.tipo === 'Link' ? 'selected' : ''}>Enlace / URL</option>
                                <option value="Protocolo" ${item.tipo === 'Protocolo' ? 'selected' : ''}>Manual / Protocolo</option>
                                <option value="Lista" ${item.tipo === 'Lista' ? 'selected' : ''}>Lista de Nombres</option>
                                <option value="Descripción" ${item.tipo === 'Descripción' ? 'selected' : ''}>Descripción Detallada</option>
                                <option value="Texto" ${item.tipo === 'Texto' ? 'selected' : ''}>Texto Plano</option>
                            </select>
                            <label>Tipo de Contenido</label>
                        </div>
                        <div class="form-field is-floating">
                            <input id="swal-key-categoria" class="dense-input" placeholder=" " value="${item.categoria}">
                            <label>Categoría</label>
                        </div>
                    </div>
                    <div class="form-field is-floating">
                        <input id="swal-key-enlace" class="dense-input" placeholder=" " value="${item.enlace || ''}">
                        <label>Enlace / URL (Opcional)</label>
                    </div>
                    <div class="form-field is-floating">
                        <textarea id="swal-key-valor" class="dense-input" rows="3" placeholder=" ">${item.valor || ''}</textarea>
                        <label>Descripción / Datos</label>
                    </div>
                </div>
            `,
            background: 'var(--color-bg)',
            color: 'var(--color-text)',
            confirmButtonColor: 'var(--color-primary)',
            customClass: {
                popup: 'swal2-v4-popup'
            },
            preConfirm: () => ({
                ...item,
                titulo: document.getElementById('swal-key-titulo').value,
                tipo: document.getElementById('swal-key-tipo').value,
                valor: document.getElementById('swal-key-valor').value,
                categoria: document.getElementById('swal-key-categoria').value,
                enlace: document.getElementById('swal-key-enlace').value
            })
        });

        if (formValues) {
            onUpdate({
                ...item,
                ...formValues,
                icono: item.icono || 'Star'
            });
        }
    };

    const handleAddCustom = async () => {
        const { value: formValues } = await Swal.fire({
            title: 'NUEVO PUNTO PERSONALIZADO',
            html: `
                <div class="swal-v4-form">
                    <div class="form-field is-floating">
                        <input id="swal-key-titulo" class="dense-input" placeholder=" ">
                        <label>Título del Punto</label>
                    </div>
                    <div class="form-grid-2">
                        <div class="form-field is-floating">
                            <select id="swal-key-tipo" class="dense-input">
                                <option value="Link">Enlace / URL</option>
                                <option value="Protocolo">Manual / Protocolo</option>
                                <option value="Lista">Lista de Nombres</option>
                                <option value="Descripción">Descripción Detallada</option>
                                <option value="Texto">Texto Plano</option>
                            </select>
                            <label>Tipo de Contenido</label>
                        </div>
                        <div class="form-field is-floating">
                            <input id="swal-key-categoria" class="dense-input" placeholder=" " value="Personalizado">
                            <label>Categoría</label>
                        </div>
                    </div>
                    <div class="form-field is-floating">
                        <input id="swal-key-enlace" class="dense-input" placeholder=" ">
                        <label>Enlace / URL (Opcional)</label>
                    </div>
                </div>
            `,
            background: 'var(--color-bg)',
            color: 'var(--color-text)',
            confirmButtonColor: 'var(--color-primary)',
            confirmButtonText: 'CREAR',
            customClass: {
                popup: 'swal2-v4-popup'
            },
            preConfirm: () => ({
                titulo: document.getElementById('swal-key-titulo').value,
                tipo: document.getElementById('swal-key-tipo').value,
                categoria: document.getElementById('swal-key-categoria').value,
                enlace: document.getElementById('swal-key-enlace').value,
                icono: 'Star'
            })
        });

        if (formValues) {
            onUpdate(formValues);
            setShowBank(false);
        }
    };

    const openLink = (url) => {
        if (!url) return;
        const finalUrl = url.trim().startsWith('http') ? url : `https://${url.trim()}`;
        window.open(finalUrl, '_blank');
    };

    // Banco de Puntos: Agrupamos todos los items base por sus categorías definidas
    const allBaseItems = Object.values(baseItems).flat();
    const bankCategories = allBaseItems.reduce((acc, item) => {
        if (!acc[item.categoria]) acc[item.categoria] = [];
        acc[item.categoria].push(item);
        return acc;
    }, {});

    return (
        <div className="key-items-modern-v2">
            <div className="key-header-actions-main">
                <h3 className="section-title-premium-small">Puntos Clave del Evento</h3>
                <button className="btn-v4 btn-v4-primary" onClick={() => setShowBank(true)}>
                    <Sparkles size={16} /> Banco de Puntos Clave
                </button>
            </div>

            <div className="key-list-container">
                {Object.entries(categories).map(([catName, items]) => (
                    <div key={catName} className="key-cat-section">
                        <div className="cat-divider">
                            <span>{catName}</span>
                            <div className="divider-line"></div>
                        </div>
                        <div className="key-table-rows">
                            {items.map(item => (
                                <div key={item.id} className={`key-row-item ${item.completado ? 'is-done' : ''}`}>
                                    <div className="row-main">
                                        <div className="row-check-area">
                                            <button
                                                className="check-bubble"
                                                onClick={() => onUpdate({ ...item, completado: !item.completado })}
                                                title={item.completado ? 'Marcar como pendiente' : 'Marcar como completado'}
                                            >
                                                {item.completado ? <CheckCircle2 size={16} /> : <Circle size={16} />}
                                            </button>
                                        </div>
                                        <div className="row-icon" title={item.icono}>{renderIcon(item.icono, 18)}</div>
                                        <div className="row-content">
                                            <h6>{item.titulo}</h6>
                                            <small className="row-val-clamped" title={item.valor}>{item.valor || 'Sin descripción...'}</small>
                                        </div>
                                        <div className="row-actions">
                                            {(item.enlace || (item.tipo === 'Link' && item.valor && item.valor.includes('http'))) && (
                                                <button
                                                    className="action-btn-mini view active-link"
                                                    onClick={() => openLink(item.enlace || item.valor)}
                                                    title="Ir al contenido / Enlace"
                                                >
                                                    <ExternalLink size={14} />
                                                </button>
                                            )}
                                            <button className="action-btn-mini view" onClick={() => handleView(item)} title="Ver detalles">
                                                <Eye size={14} />
                                            </button>
                                            <button className="action-btn-mini edit" onClick={() => handleEdit(item)} title="Editar">
                                                <Pencil size={14} />
                                            </button>
                                            {userRol !== 'cliente' && (
                                                <button className="action-btn-mini delete" onClick={() => onDelete(item.id)} title="Borrar">
                                                    <Trash2 size={14} />
                                                </button>
                                            )}
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                ))}
            </div>

            {/* BANCO DE PUNTOS OVERLAY */}
            {showBank && createPortal(
                <div className="key-bank-overlay">
                    <div className="bank-card">
                        <div className="bank-header">
                            <div className="header-left">
                                <h2><Sparkles size={28} style={{ color: '#D4AF37' }} /> Banco de Puntos Sugeridos</h2>
                                <p style={{ color: '#A0A0A0', fontSize: '14px' }}>Selecciona los elementos que no deben faltar en este evento</p>
                            </div>
                            <button className="btn-v4 btn-mini" style={{ width: '40px', height: '40px', padding: '0', display: 'flex', alignItems: 'center', justifyCenter: 'center' }} onClick={() => setShowBank(false)} title="Cerrar Banco">
                                <X size={20} />
                            </button>
                        </div>

                        <div className="bank-search-bar">
                            <Search size={18} />
                            <input
                                type="text"
                                placeholder="Buscar punto clave (ej: Canción, Menú...)"
                                value={searchTerm}
                                onChange={(e) => setSearchTerm(e.target.value)}
                            />
                            <button className="btn-v4 btn-mini" onClick={handleAddCustom}>+ Personalizado</button>
                        </div>

                        <div className="bank-grid">
                            {Object.entries(bankCategories).map(([cat, points]) => {
                                const filtered = points.filter(p => p.titulo.toLowerCase().includes(searchTerm.toLowerCase()));
                                if (filtered.length === 0) return null;
                                return (
                                    <div key={cat} className="bank-cat-col">
                                        <h4>{cat}</h4>
                                        <div className="bank-items-stack">
                                            {filtered.map((p, idx) => {
                                                const isAlreadyAdded = keyItems.some(ki => ki.titulo === p.titulo);
                                                return (
                                                    <button
                                                        key={idx}
                                                        className={`bank-item-btn ${isAlreadyAdded ? 'added' : ''}`}
                                                        onClick={() => {
                                                            if (!isAlreadyAdded) {
                                                                onUpdate(p);
                                                                setShowBank(false);
                                                            }
                                                        }}
                                                        disabled={isAlreadyAdded}
                                                    >
                                                        <div className="item-icon">{renderIcon(p.icono, 14)}</div>
                                                        <span className="item-title">{p.titulo}</span>
                                                        {isAlreadyAdded ? <CheckCircle2 size={14} /> : <Plus size={14} />}
                                                    </button>
                                                );
                                            })}
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default KeyItemsManager;
